import { useState, useRef, useEffect } from "react";
import { Upload, FileText, X, Loader2 } from "lucide-react";
import type { UploadFormData } from "../../../types/admin";
import { ACADEMIC_YEARS, CATEGORIES } from "../../../types/admin";

export const getDefaultFormData = (
  years: number[] = ACADEMIC_YEARS,
): UploadFormData => {
  const currentYear = new Date().getFullYear();
  return {
    file: null,
    year: years.includes(currentYear) ? currentYear : (years[0] ?? currentYear),
    category: "",
    description: "",
  };
};

interface UploadFormProps {
  onSubmit: (data: UploadFormData) => Promise<boolean>;
  isUploading: boolean;
  defaultValues: UploadFormData;
  availableYears?: number[];
  availableCategories?: string[];
}

const UPLOAD_STEPS = [
  "─Éang tß║úi file l├¬n server...",
  "─Éang ph├ón t├¡ch t├ái liß╗çu...",
  "─Éang chia chunks & embedding...",
  "─Éang l╞░u v├áo Knowledge Base...",
];

export const UploadForm = ({
  onSubmit,
  isUploading,
  defaultValues,
  availableYears = ACADEMIC_YEARS,
  availableCategories = CATEGORIES,
}: UploadFormProps) => {
  const [formData, setFormData] = useState<UploadFormData>(defaultValues);
  const [dragActive, setDragActive] = useState(false);
  const [uploadStep, setUploadStep] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Simulate upload progress steps
  useEffect(() => {
    if (!isUploading) {
      setUploadStep(0);
      return;
    }
    const interval = setInterval(() => {
      setUploadStep((prev) =>
        prev < UPLOAD_STEPS.length - 1 ? prev + 1 : prev,
      );
    }, 4000);
    return () => clearInterval(interval);
  }, [isUploading]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFormData((prev: UploadFormData) => ({
        ...prev,
        file: e.target.files![0],
      }));
    }
  };

  const removeFile = () => {
    setFormData((prev: UploadFormData) => ({ ...prev, file: null }));
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.file) {
      alert("Vui l├▓ng chß╗ìn file (PDF, TXT, DOCX, RTF, CSV, JPG, PNG)");
      return;
    }

    if (!formData.category) {
      alert("Vui l├▓ng chß╗ìn danh mß╗Ñc");
      return;
    }

    const success = await onSubmit(formData);

    if (success) {
      setFormData(defaultValues);
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
    }
  };

  const progressPercent = isUploading
    ? Math.min(((uploadStep + 1) / UPLOAD_STEPS.length) * 100, 95)
    : 0;

  return (
    <form
      onSubmit={handleSubmit}
      className="h-full flex flex-col"
    >
      <h2 className="text-base font-semibold text-gray-800 mb-5 flex items-center gap-2">
        <Upload className="w-[18px] h-[18px] text-blue-600" />
        Upload T├ái Liß╗çu
      </h2>

      {/* File Drop Zone */}
      <div
        className={`relative border-2 border-dashed rounded-xl p-6 text-center transition-colors mb-5
          ${dragActive ? "border-blue-500 bg-blue-50" : "border-gray-200 hover:border-gray-300"}
          ${formData.file ? "bg-emerald-50/50 border-emerald-300" : ""}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <input
          ref={fileInputRef}
          type="file"
          accept=".pdf,.txt,.docx,.rtf,.csv,.jpg,.jpeg,.png"
          onChange={handleFileChange}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
          disabled={isUploading}
        />

        {formData.file ? (
          <div className="flex items-center justify-center gap-3">
            <FileText className="w-7 h-7 text-emerald-600" />
            <div className="text-left">
              <p className="font-medium text-gray-800 text-sm">
                {formData.file.name}
              </p>
              <p className="text-xs text-gray-500">
                {(formData.file.size / 1024 / 1024).toFixed(2)} MB
              </p>
            </div>
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                removeFile();
              }}
              disabled={isUploading}
              className="ml-3 p-1 hover:bg-red-100 rounded-full transition-colors"
            >
              <X className="w-4 h-4 text-red-500" />
            </button>
          </div>
        ) : (
          <div>
            <Upload className="w-10 h-10 mx-auto text-gray-300 mb-2" />
            <p className="text-sm text-gray-600 font-medium">
              K├⌐o thß║ú hoß║╖c click ─æß╗â chß╗ìn
            </p>
            <p className="text-xs text-gray-400 mt-1">
              PDF, TXT, DOCX, RTF, CSV, JPG, PNG
            </p>
          </div>
        )}
      </div>

      {/* Form Fields */}
      <div className="grid grid-cols-2 gap-3 mb-4">
        <div>
          <label className="block text-xs font-medium text-gray-600 mb-1.5">
            N─âm hß╗ìc <span className="text-red-500">*</span>
          </label>
          <select
            value={formData.year}
            onChange={(e) =>
              setFormData((prev: UploadFormData) => ({
                ...prev,
                year: Number(e.target.value),
              }))
            }
            disabled={isUploading}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
          >
            {availableYears.map((year) => (
              <option key={year} value={year}>
                {year}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-xs font-medium text-gray-600 mb-1.5">
            Danh mß╗Ñc <span className="text-red-500">*</span>
          </label>
          <select
            value={formData.category}
            onChange={(e) =>
              setFormData((prev: UploadFormData) => ({
                ...prev,
                category: e.target.value,
              }))
            }
            disabled={isUploading}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
            required
          >
            <option value="">-- Chß╗ìn --</option>
            {availableCategories.map((cat) => (
              <option key={cat} value={cat}>
                {cat}
              </option>
            ))}
          </select>
        </div>
      </div>

      {formData.category === "─Éiß╗âm chuß║⌐n" && (
        <div className="mb-4 p-3 bg-blue-50/80 border border-blue-200 rounded-lg flex items-start gap-2 text-sm text-blue-800">
          <div className="shrink-0 mt-0.5">≡ƒÆí</div>
          <div>
            <strong>L╞░u ├╜:</strong> Vui l├▓ng upload bß║▒ng file <strong>.CSV</strong> ─æß╗â dß╗» liß╗çu ─æiß╗âm chuß║⌐n ─æ╞░ß╗úc cß║¡p nhß║¡t ch├¡nh x├íc tuyß╗çt ─æß╗æi. File CSV cß║ºn giß╗» nguy├¬n c├íc cß╗Öt chß╗⌐a chß╗» <code>MaNganh</code> v├á <code>NganhHoc</code>. C├íc cß╗Öt ─æiß╗âm c├▓n lß║íi (VD: PT1, PT2) hß╗ç thß╗æng sß║╜ tß╗▒ ─æß╗Öng qu├⌐t.
          </div>
        </div>
      )}

      {/* Description */}
      <div className="mb-5">
        <label className="block text-xs font-medium text-gray-600 mb-1.5">
          M├┤ tß║ú (t├╣y chß╗ìn)
        </label>
        <textarea
          value={formData.description}
          onChange={(e) =>
            setFormData((prev: UploadFormData) => ({
              ...prev,
              description: e.target.value,
            }))
          }
          disabled={isUploading}
          placeholder="Nhß║¡p m├┤ tß║ú ngß║»n vß╗ü t├ái liß╗çu..."
          rows={2}
          className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors resize-none"
        />
      </div>

      {/* Upload Progress Indicator */}
      {isUploading && (
        <div className="mb-5 p-4 bg-blue-50 rounded-xl border border-blue-100">
          <div className="flex items-center gap-2 mb-3">
            <Loader2 className="w-4 h-4 text-blue-600 animate-spin" />
            <span className="text-sm font-medium text-blue-700">
              {UPLOAD_STEPS[uploadStep]}
            </span>
          </div>
          <div className="w-full bg-blue-100 rounded-full h-1.5">
            <div
              className="bg-blue-600 h-1.5 rounded-full transition-all duration-700 ease-out"
              style={{ width: `${progressPercent}%` }}
            />
          </div>
          <div className="flex justify-between mt-1.5">
            <span className="text-[11px] text-blue-500">
              B╞░ß╗¢c {uploadStep + 1}/{UPLOAD_STEPS.length}
            </span>
            <span className="text-[11px] text-blue-500">
              {Math.round(progressPercent)}%
            </span>
          </div>
        </div>
      )}

      {/* Submit Button */}
      <button
        type="submit"
        disabled={isUploading || !formData.file || !formData.category}
        className={`mt-2 w-full py-2.5 px-4 rounded-lg text-sm font-medium text-white transition-all flex items-center justify-center gap-2
          ${
            isUploading || !formData.file || !formData.category
              ? "bg-gray-300 cursor-not-allowed"
              : "bg-blue-600 hover:bg-blue-700 active:scale-[0.98] shadow-sm"
          }`}
      >
        {isUploading ? (
          <>
            <Loader2 className="w-4 h-4 animate-spin" />
            ─Éang xß╗¡ l├╜...
          </>
        ) : (
          <>
            <Upload className="w-4 h-4" />
            Upload & Nß║íp Knowledge Base
          </>
        )}
      </button>
    </form>
  );
};

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  uploadDocument,
  getDocuments,
  deleteDocument,
  getMetadataOptions,
} from "../api/adminAPI";
import {
  ACADEMIC_YEARS,
  CATEGORIES,
  type UploadFormData,
} from "../../../types/admin";

export const useDocuments = () => {
  const queryClient = useQueryClient();

  const documentsQuery = useQuery({
    queryKey: ["documents"],
    queryFn: getDocuments,
  });

  const uploadMutation = useMutation({
    mutationFn: (formData: UploadFormData) => {
      if (!formData.file) throw new Error("Vui l├▓ng chß╗ìn file PDF");
      return uploadDocument(
        formData.file,
        formData.year,
        formData.category,
        formData.description || undefined,
      );
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["documents"] });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (docUuid: string) => deleteDocument(docUuid),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["documents"] });
    },
  });

  const metadataOptionsQuery = useQuery({
    queryKey: ["admin-metadata-options"],
    queryFn: getMetadataOptions,
    staleTime: 5 * 60 * 1000,
    retry: 1,
    initialData: {
      years: ACADEMIC_YEARS,
      categories: CATEGORIES,
    },
  });

  return {
    documents: documentsQuery.data || [],
    isLoading: documentsQuery.isPending || documentsQuery.isFetching,
    error: documentsQuery.error
      ? "Kh├┤ng thß╗â tß║úi danh s├ích t├ái liß╗çu. Vui l├▓ng thß╗¡ lß║íi."
      : null,

    isUploading: uploadMutation.isPending,
    uploadError: uploadMutation.error
      ? (uploadMutation.error as any).response?.data?.detail ||
        "Lß╗ùi khi upload. Vui l├▓ng thß╗¡ lß║íi."
      : null,
    uploadSuccess: uploadMutation.isSuccess ? "Upload th├ánh c├┤ng!" : null,

    uploadDocument: uploadMutation.mutateAsync,
    deleteDocument: deleteMutation.mutateAsync,

    metadataOptions: metadataOptionsQuery.data,
    isLoadingMetadataOptions: metadataOptionsQuery.isPending,
    metadataOptionsError: metadataOptionsQuery.error
      ? "Kh├┤ng thß╗â tß║úi metadata options. ─Éang d├╣ng dß╗» liß╗çu mß║╖c ─æß╗ïnh."
      : null,

    refetchDocuments: documentsQuery.refetch,
    resetUploadState: uploadMutation.reset,
  };
};

import { create } from "zustand";
import { persist } from "zustand/middleware";
import { loginAPI } from "../api/authAPI";

interface AuthState {
    token: string | null;
    isAuthenticated: boolean;
    isLoggingIn: boolean;
    loginError: string | null;

    login: (username: string, password: string) => Promise<boolean>;
    logout: () => void;
    clearError: () => void;
}

export const useAuthStore = create<AuthState>()(
    persist(
        (set) => ({
            token: null,
            isAuthenticated: false,
            isLoggingIn: false,
            loginError: null,

            login: async (username, password) => {
                set({ isLoggingIn: true, loginError: null });
                try {
                    const data = await loginAPI(username, password);
                    set({
                        token: data.access_token,
                        isAuthenticated: true,
                        isLoggingIn: false,
                    });
                    return true;
                } catch (err: any) {
                    const message =
                        err.response?.data?.detail || "─É─âng nhß║¡p thß║Ñt bß║íi. Vui l├▓ng thß╗¡ lß║íi.";
                    set({ loginError: message, isLoggingIn: false });
                    return false;
                }
            },

            logout: () => {
                set({ token: null, isAuthenticated: false, loginError: null });
            },

            clearError: () => set({ loginError: null }),
        }),
        {
            name: "admin_auth_storage",
            partialize: (state) => ({ token: state.token, isAuthenticated: state.isAuthenticated }),
        },
    ),
);

import axios, { AxiosError } from "axios";
import type {
  ChatResponse,
  ChatRequest,
  ResetConversationResponse,
  StreamMetadata,
} from "../../../types/chat";

// Use relative path for Vite proxy, or full URL for production
const API_BASE_URL = import.meta.env.VITE_API_URL || "";

// Configure axios defaults
axios.defaults.timeout = 60000; // 60 seconds timeout
axios.defaults.headers.post["Content-Type"] = "application/json";

// ============================================
// SSE STREAMING CALLBACKS
// ============================================

export interface StreamCallbacks {
  /** Called with each text token as it arrives */
  onToken: (token: string) => void;
  /** Called once when metadata (session_id, intent) is received */
  onMetadata?: (meta: StreamMetadata) => void;
  /** Called once when sources are available (RAG queries) */
  onSources?: (sources: string[]) => void;
  /** Called when the stream is fully complete */
  onDone: () => void;
  /** Called if an error occurs during streaming */
  onError: (error: Error) => void;
}

/**
 * Send a chat message and stream the response via SSE.
 * Uses the native fetch API + ReadableStream to process events.
 *
 * @param message - The user's message
 * @param conversationId - Optional session ID for continuity
 * @param callbacks - Handlers for stream events
 * @returns An AbortController so the caller can cancel the stream
 */
export const sendMessageStream = (
  message: string,
  conversationId: string | undefined,
  callbacks: StreamCallbacks,
): AbortController => {
  const controller = new AbortController();
  const endpoint = `${API_BASE_URL}/api/v1/chat/stream`;

  const body: ChatRequest = {
    message: message.trim(),
    conversation_id: conversationId,
  };

  // Run the async streaming logic
  (async () => {
    try {
      const response = await fetch(endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
        signal: controller.signal,
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(
          `HTTP ${response.status}: ${errorText || "Lß╗ùi kß║┐t nß╗æi server"}`,
        );
      }

      const reader = response.body?.getReader();
      if (!reader) {
        throw new Error(
          "ReadableStream kh├┤ng ─æ╞░ß╗úc hß╗ù trß╗ú tr├¬n tr├¼nh duyß╗çt n├áy.",
        );
      }

      const decoder = new TextDecoder();
      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });

        // Parse SSE lines from buffer
        const lines = buffer.split("\n");
        // Keep the last (possibly incomplete) line in the buffer
        buffer = lines.pop() || "";

        let currentEvent = "";
        let dataLines: string[] = [];

        for (const line of lines) {
          if (line.startsWith("event: ")) {
            // If we had a previous event with data, process it first
            if (currentEvent && dataLines.length > 0) {
              processSSEEvent(currentEvent, dataLines.join("\n"), callbacks);
            }
            currentEvent = line.slice(7).trim();
            dataLines = [];
          } else if (line.startsWith("data: ")) {
            dataLines.push(line.slice(6));
          } else if (line === "" && currentEvent && dataLines.length > 0) {
            // Empty line = end of event
            processSSEEvent(currentEvent, dataLines.join("\n"), callbacks);
            currentEvent = "";
            dataLines = [];
          }
        }

        // Process any remaining event in progress
        if (currentEvent && dataLines.length > 0) {
          processSSEEvent(currentEvent, dataLines.join("\n"), callbacks);
          currentEvent = "";
          dataLines = [];
        }
      }

      // Process any remaining buffer
      if (buffer.trim()) {
        const remaining = buffer.split("\n");
        let currentEvent = "";
        let dataLines: string[] = [];
        for (const line of remaining) {
          if (line.startsWith("event: ")) {
            if (currentEvent && dataLines.length > 0) {
              processSSEEvent(currentEvent, dataLines.join("\n"), callbacks);
            }
            currentEvent = line.slice(7).trim();
            dataLines = [];
          } else if (line.startsWith("data: ")) {
            dataLines.push(line.slice(6));
          }
        }
        if (currentEvent && dataLines.length > 0) {
          processSSEEvent(currentEvent, dataLines.join("\n"), callbacks);
        }
      }

      callbacks.onDone();
    } catch (err: unknown) {
      // Ignore abort errors (user cancelled)
      if (err instanceof DOMException && err.name === "AbortError") {
        callbacks.onDone();
        return;
      }

      const error =
        err instanceof Error
          ? err
          : new Error("─É├ú xß║úy ra lß╗ùi kh├┤ng x├íc ─æß╗ïnh khi streaming.");

      console.error("[Stream Error]", error);
      callbacks.onError(error);
    }
  })();

  return controller;
};

/** Parse a single SSE event and call the appropriate callback */
function processSSEEvent(
  event: string,
  data: string,
  callbacks: StreamCallbacks,
) {
  switch (event) {
    case "token":
      callbacks.onToken(data);
      break;
    case "metadata":
      try {
        const meta: StreamMetadata = JSON.parse(data);
        callbacks.onMetadata?.(meta);
      } catch {
        console.warn("Failed to parse metadata:", data);
      }
      break;
    case "sources":
      try {
        const sources: string[] = JSON.parse(data);
        callbacks.onSources?.(sources);
      } catch {
        console.warn("Failed to parse sources:", data);
      }
      break;
    case "done":
      // Will be handled by the reader loop ending
      break;
    case "error":
      try {
        const errData = JSON.parse(data);
        callbacks.onError(new Error(errData.error || "Stream error"));
      } catch {
        callbacks.onError(new Error(data));
      }
      break;
    default:
      console.warn("Unknown SSE event:", event, data);
  }
}

// ============================================
// LEGACY NON-STREAMING API (kept for fallback)
// ============================================

/**
 * Send a chat message to the server (non-streaming fallback)
 */
export const sendMessage = async (
  message: string,
  conversationId?: string,
): Promise<ChatResponse> => {
  // Validate input
  if (!message || !message.trim()) {
    throw new Error("Tin nhß║»n kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng");
  }

  const endpoint = `${API_BASE_URL}/api/v1/chat`;
  console.log(`Sending request to: ${endpoint}`);
  console.log(`Message: ${message.substring(0, 50)}...`);
  if (conversationId) {
    console.log(`Conversation ID: ${conversationId}`);
  }

  try {
    const requestBody: ChatRequest = {
      message: message.trim(),
      conversation_id: conversationId,
    };

    const response = await axios.post(endpoint, requestBody);

    console.log("Response received:", response.status);
    console.log("Data:", response.data);

    // Validate response structure
    if (!response.data || typeof response.data.response !== "string") {
      throw new Error("Invalid response format from server");
    }

    // Return response with conversation_id
    return {
      response: response.data.response,
      sources: response.data.sources || [],
      conversation_id: response.data.conversation_id,
    };
  } catch (error) {
    console.error("API Error:", error);

    // Handle specific error types
    if (axios.isAxiosError(error)) {
      const axiosError = error as AxiosError;

      // Network error
      if (!axiosError.response) {
        if (axiosError.code === "ECONNREFUSED") {
          throw new Error(
            "Kh├┤ng thß╗â kß║┐t nß╗æi tß╗¢i server. Vui l├▓ng kiß╗âm tra backend ─æang chß║íy tß║íi " +
            API_BASE_URL,
          );
        }
        if (
          axiosError.code === "ETIMEDOUT" ||
          axiosError.message.includes("timeout")
        ) {
          throw new Error(
            "Request timeout. Server mß║Ñt qu├í nhiß╗üu thß╗¥i gian ─æß╗â trß║ú lß╗¥i.",
          );
        }
        throw new Error("Lß╗ùi kß║┐t nß╗æi. Vui l├▓ng kiß╗âm tra internet v├á thß╗¡ lß║íi.");
      }

      // Server error with response
      const status = axiosError.response.status;
      const errorData = axiosError.response.data as any;

      if (status === 500) {
        const errorMsg =
          errorData?.detail?.message || errorData?.detail || "Lß╗ùi server";
        throw new Error(`Lß╗ùi server: ${errorMsg}`);
      }

      if (status === 400) {
        const errorMsg = errorData?.detail?.message || "Dß╗» liß╗çu kh├┤ng hß╗úp lß╗ç";
        throw new Error(errorMsg);
      }

      if (status === 422) {
        throw new Error("Dß╗» liß╗çu kh├┤ng hß╗úp lß╗ç. Vui l├▓ng kiß╗âm tra tin nhß║»n.");
      }

      if (status === 404) {
        throw new Error(
